function calcScores(ap){var db=AB.dailyBudget||800;var tCPA=AB.targetCPA||25;var mo=0;ap.forEach(function(p){if(p.ord>mo)mo=p.ord;});var mc=0;ap.forEach(function(p){if(p.cv>mc)mc=p.cv;});var sc=ap.map(function(p){var s=0;if(p.cpa>0){var r=Math.max(0,1-(p.cpa-tCPA*0.3)/(tCPA*3));s+=Math.min(r,1)*25;}s+=Math.min(p.iqk/50,1)*15;s+=(p.cv/(mc||1))*15;if(p.isSearch)s+=20;s+=Math.min((p.ord||0)/(mo||1),1)*15;var rec=(p.ld>="2026-06-10")?5:(p.ld>="2026-06-01"?3:(p.ld>="2026-05-01"?1:0));s+=rec;s+=Math.min(1,p.dc/30)*5;return{n:p.n,cpa:p.cpa,iqk:p.iqk,ord:p.ord||0,isSearch:p.isSearch,score:Math.max(s,1)};});var ts=0;sc.forEach(function(p){ts+=p.score;});ts=ts||1;var al=sc.map(function(p){return{n:p.n,cpa:p.cpa,iqk:p.iqk,ord:p.ord,isSearch:p.isSearch,score:p.score,pct:p.score/ts*100,alloc:Math.round(p.score/ts*db)};}).sort(function(a,b){return b.score-a.score;});var valid=al.filter(function(p){return p.cpa>0;});var vts=0;valid.forEach(function(p){vts+=p.score;});vts=vts||1;var val=valid.map(function(p){return{n:p.n,cpa:p.cpa,iqk:p.iqk,ord:p.ord,isSearch:p.isSearch,score:p.score,pct:p.score/vts*100,alloc:Math.round(p.score/vts*db)};}).sort(function(a,b){return b.score-a.score;});return val.filter(function(p){return p.pct>=1;});}
